     2→/**
     3→ * Ralph Output Formatter
     4→ *
     5→ * A richer Node.js alternative to format-output.sh
     6→ * Provides color-coded output, timing, progress spinners, and cleaner formatting
     7→ *
     8→ * Usage: cat stream.json | node output-formatter.js
     9→ */
    10→
    11→const readline = require('readline');
    12→
    13→// ANSI color codes
    14→const colors = {
    15→  reset: '\x1b[0m',
    16→  bold: '\x1b[1m',
    17→  dim: '\x1b[2m',
    18→  cyan: '\x1b[36m',
    19→  yellow: '\x1b[33m',
    20→  green: '\x1b[32m',
    21→  red: '\x1b[31m',
    22→  magenta: '\x1b[35m',
    23→  blue: '\x1b[34m',
    24→  white: '\x1b[37m',
    25→};
    26→
    27→// Spinner frames
    28→const spinnerFrames = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
    29→let spinnerIndex = 0;
    30→let spinnerInterval = null;
    31→let currentToolName = '';
    32→
    33→// Configuration
    34→const MAX_CONTENT_LENGTH = 500;
    35→const MAX_TOOL_INPUT_LENGTH = 200;
    36→
    37→// State
    38→let messageStartTime = null;
    39→let toolStartTime = null;
    40→let totalCost = 0;
    41→
    42→function truncate(text, maxLen = MAX_CONTENT_LENGTH) {
    43→  if (!text) return '';
    44→  const str = String(text);
    45→  if (str.length <= maxLen) return str;
    46→  return str.substring(0, maxLen) + '... (truncated)';
    47→}
    48→
    49→function formatDuration(ms) {
    50→  if (ms < 1000) return `${ms}ms`;
    51→  if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
    52→  return `${(ms / 60000).toFixed(1)}m`;
    53→}
    54→
    55→function startSpinner(toolName) {
    56→  currentToolName = toolName;
    57→  stopSpinner();
    58→  spinnerInterval = setInterval(() => {
    59→    const frame = spinnerFrames[spinnerIndex % spinnerFrames.length];
    60→    process.stdout.write(`\r${colors.yellow}${frame}${colors.reset} ${colors.bold}${currentToolName}${colors.reset}  `);
    61→    spinnerIndex++;
    62→  }, 80);
    63→}
    64→
    65→function stopSpinner() {
    66→  if (spinnerInterval) {
    67→    clearInterval(spinnerInterval);
    68→    spinnerInterval = null;
    69→    process.stdout.write('\r\x1b[K'); // Clear line
    70→  }
    71→}
    72→
    73→function log(prefix, color, message) {
    74→  stopSpinner();
    75→  console.log(`${color}${prefix}${colors.reset} ${message}`);
    76→}
    77→
    78→function processLine(line) {
