};

// Spinner frames
const spinnerFrames = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
let spinnerIndex = 0;
let spinnerInterval = null;
let currentToolName = '';

// Configuration
const MAX_CONTENT_LENGTH = 500;
const MAX_TOOL_INPUT_LENGTH = 200;

// State
let messageStartTime = null;
let toolStartTime = null;
let totalCost = 0;

function truncate(text, maxLen = MAX_CONTENT_LENGTH) {
  if (!text) return '';
  const str = String(text);
  if (str.length <= maxLen) return str;
  return str.substring(0, maxLen) + '... (truncated)';
}

function formatDuration(ms) {
  if (ms < 1000) return `${ms}ms`;
  if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
  return `${(ms / 60000).toFixed(1)}m`;
}

function startSpinner(toolName) {
  currentToolName = toolName;
  stopSpinner();
  spinnerInterval = setInterval(() => {
    const frame = spinnerFrames[spinnerIndex % spinnerFrames.length];
    process.stdout.write(`\r${colors.yellow}${frame}${colors.reset} ${colors.bold}${currentToolName}${colors.reset}  `);
    spinnerIndex++;
  }, 80);
}

function stopSpinner() {
  if (spinnerInterval) {
    clearInterval(spinnerInterval);
    spinnerInterval = null;
    process.stdout.write('\r\x1b[K'); // Clear line
  }
}

function log(prefix, color, message) {
  stopSpinner();
  console.log(`${color}${prefix}${colors.reset} ${message}`);
}

function processLine(line) {
  if (!line.trim()) return;

  // Handle stream-json format (lines starting with "data: ")
  if (line.startsWith('data: ')) {
    line = line.substring(6); // Remove "data: " prefix
  } else if (line.startsWith('event:') || line === ':') {
    // Skip event lines and heartbeat lines
    return;
  }

  let data;
  try {
    data = JSON.parse(line);
  } catch {
    // Not JSON, output as-is
    console.log(line);
    return;
  }

  const type = data.type;

  switch (type) {
    case 'assistant': {
      const content = data.message?.content;
      if (content) {
        if (Array.isArray(content)) {
          content.forEach(block => {
            if (block.type === 'text' && block.text) {
              log('', colors.cyan, block.text);
            }
          });
        } else {
          log('', colors.cyan, content);
        }
      }
      break;
    }

    case 'content_block_start': {
      const blockType = data.content_block?.type;
      if (blockType === 'tool_use') {
        const toolName = data.content_block?.name || 'unknown';
        toolStartTime = Date.now();
        startSpinner(toolName);
      }
      break;
    }

    case 'content_block_delta': {
      const deltaType = data.delta?.type;
      if (deltaType === 'text_delta' && data.delta?.text) {
        stopSpinner();
        process.stdout.write(`${colors.cyan}${data.delta.text}${colors.reset}`);
      }
      // Ignore input_json_delta - it's streaming tool input
      break;
    }

    case 'content_block_stop': {
      // End of content block
      break;
    }

    case 'tool_use': {
      stopSpinner();
      const toolName = data.name || 'unknown';
      const input = data.input ? JSON.stringify(data.input) : '{}';
      log('[tool]', colors.yellow, `${colors.bold}${toolName}${colors.reset}`);
      console.log(`${colors.dim}  input: ${truncate(input, MAX_TOOL_INPUT_LENGTH)}${colors.reset}`);
      toolStartTime = Date.now();
      startSpinner(toolName);
      break;
    }

    case 'tool_result': {
      stopSpinner();
      const isError = data.is_error;
      const duration = toolStartTime ? formatDuration(Date.now() - toolStartTime) : '';

      if (isError) {
        log('[error]', colors.red, `Tool failed ${duration ? `(${duration})` : ''}`);
        if (data.content) {
          console.log(`${colors.red}  ${truncate(data.content, 300)}${colors.reset}`);
        }
      } else {
        log('[done]', colors.green, `Tool completed ${duration ? `(${duration})` : ''}`);
      }
      toolStartTime = null;
      break;
    }

    case 'error': {
      stopSpinner();
      const errorMsg = data.error?.message || data.message || 'Unknown error';
      log('[ERROR]', colors.red, errorMsg);
      break;
    }

    case 'message_start': {
      messageStartTime = Date.now();
      const model = data.message?.model;
      if (model) {
        console.log(`${colors.dim}[model: ${model}]${colors.reset}`);
      }
      break;
    }

    case 'message_stop': {
      stopSpinner();
      console.log('');
      break;
    }

    case 'message_delta': {
      // Message metadata update
      const usage = data.usage;
      if (usage) {
        const tokens = usage.output_tokens || 0;
        console.log(`${colors.dim}[tokens: ${tokens}]${colors.reset}`);
      }
      break;
    }

    case 'system': {
      const text = data.message;
      if (text) {
        log('[system]', colors.magenta, text);
      }
      break;
    }

    case 'result': {
      stopSpinner();
      const cost = data.cost_usd;
      const duration = data.duration_ms;
      const parts = [];
      if (cost) {
        totalCost += parseFloat(cost);
        parts.push(`cost: $${cost}`);
      }
      if (duration) {
        parts.push(`duration: ${formatDuration(duration)}`);
      }
      if (parts.length > 0) {
        console.log(`${colors.dim}[stats] ${parts.join(', ')}${colors.reset}`);
      }
      break;
    }

    default: {
      // Check for subagent info
      if (data.subagent) {
        log('[subagent]', colors.magenta, data.subagent);
      }
      break;
    }
  }
}

// Main
const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
  terminal: false
});

rl.on('line', processLine);

rl.on('close', () => {
  stopSpinner();
  if (totalCost > 0) {
    console.log(`\n${colors.dim}[session total] $${totalCost.toFixed(4)}${colors.reset}`);
  }
});

// Handle Ctrl+C gracefully
process.on('SIGINT', () => {
  stopSpinner();
  process.exit(0);
});

#!/usr/bin/env python3
"""
Simple proxy to strip Anthropic-specific 'thinking' params before forwarding to LiteLLM.
Listens on port 4001, forwards to LiteLLM on port 4000.
"""

import json
import os
from http.server import HTTPServer, BaseHTTPRequestHandler
import urllib.request
import urllib.error

LITELLM_URL = os.environ.get("LITELLM_URL", "http://localhost:4000")


class ProxyHandler(BaseHTTPRequestHandler):
    def log_message(self, format, *args):
        # Quieter logging
        pass

    def do_GET(self):
        """Forward GET requests (health checks, etc)."""
        self._proxy_request()

    def do_POST(self):
        """Forward POST requests, stripping thinking params from body."""
        self._proxy_request(strip_thinking=True)

    def _proxy_request(self, strip_thinking=False):
        # Read request body if present
        content_length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(content_length) if content_length > 0 else None

        # Strip thinking params from JSON body
        if strip_thinking and body:
            try:
                data = json.loads(body)
                modified = self._strip_thinking_params(data)
                if modified:
                    print(f"[proxy] Stripped thinking params from request to {self.path}")
                body = json.dumps(data).encode("utf-8")
            except json.JSONDecodeError:
                pass  # Not JSON, forward as-is

        # Build target URL
        target_url = f"{LITELLM_URL}{self.path}"

        # Build headers (forward most, skip hop-by-hop)
        headers = {}
        skip_headers = {"host", "connection", "keep-alive", "transfer-encoding"}
        for key, value in self.headers.items():
            if key.lower() not in skip_headers:
                headers[key] = value

        # Update content-length if body was modified
        if body:
            headers["Content-Length"] = str(len(body))

        # Make request to LiteLLM
        try:
            req = urllib.request.Request(
                target_url,
                data=body,
                headers=headers,
                method=self.command,
            )
            with urllib.request.urlopen(req) as response:
                self.send_response(response.status)
                for key, value in response.headers.items():
                    if key.lower() not in {"transfer-encoding", "connection"}:
                        self.send_header(key, value)
                self.end_headers()
                self.wfile.write(response.read())
        except urllib.error.HTTPError as e:
            self.send_response(e.code)
            for key, value in e.headers.items():
                if key.lower() not in {"transfer-encoding", "connection"}:
                    self.send_header(key, value)
            self.end_headers()
            self.wfile.write(e.read())
        except urllib.error.URLError as e:
            print(f"[proxy] Connection error to {target_url}: {e.reason}")
            self.send_response(503)
            self.end_headers()
            self.wfile.write(f"Service unavailable: {e.reason}".encode())
        except ConnectionRefusedError as e:
            print(f"[proxy] LiteLLM connection refused at {LITELLM_URL}")
            self.send_response(503)
            self.end_headers()
            self.wfile.write(b"LiteLLM service is not available")
        except (ConnectionResetError, BrokenPipeError) as e:
            print(f"[proxy] Connection reset while proxying: {e}")
            self.send_response(502)
            self.end_headers()
            self.wfile.write(b"Connection interrupted")
        except OSError as e:
            print(f"[proxy] OS/network error: {e}")
            self.send_response(502)
            self.end_headers()
            self.wfile.write(f"Network error: {e}".encode())
        except Exception as e:
            print(f"[proxy] Unexpected error: {type(e).__name__}: {e}")
            self.send_response(500)
            self.end_headers()
            self.wfile.write(f"Internal proxy error: {type(e).__name__}".encode())

    def _strip_thinking_params(self, data):
        """Recursively strip thinking-related params. Returns True if modified."""
        modified = False
        thinking_keys = {
            "thinking",
            "extended_thinking",
            "thinking_budget",
            "budget_tokens",
        }

        if isinstance(data, dict):
            for key in list(data.keys()):
                if key in thinking_keys:
                    del data[key]
                    modified = True
                elif isinstance(data[key], (dict, list)):
                    if self._strip_thinking_params(data[key]):
                        modified = True
        elif isinstance(data, list):
            for item in data:
                if isinstance(item, (dict, list)):
                    if self._strip_thinking_params(item):
                        modified = True

        return modified


def main():
    port = int(os.environ.get("PROXY_PORT", 4001))
    server = HTTPServer(("0.0.0.0", port), ProxyHandler)
    print(f"[proxy] Listening on port {port}, forwarding to {LITELLM_URL}")
    print("[proxy] Will strip thinking params from requests")
    server.serve_forever()


if __name__ == "__main__":
    main()

